{"content":"package com.pinterest.ktlint.ruleset.standard.rules

import com.pinterest.ktlint.rule.engine.core.api.editorconfig.MAX_LINE_LENGTH_PROPERTY
import com.pinterest.ktlint.test.KtLintAssertThat.Companion.assertThatRule
import org.junit.jupiter.api.Test

class FunctionReturnTypeSpacingRuleMaxLineLengthTest {
    private val functionReturnTypeSpacingRuleAssertThat = assertThatRule { FunctionReturnTypeSpacingRule() }

    @Test
    fun `Given a parameterless function with a long name and a long return type which would exceed the max line length then do not reformat`() {
        val code =
            """
            fun thisIsAVeryVeryVeryVeryVeryVeryVeryVeryVeryVeryVeryVeryVeryVeryVeryVeryVeryVeryVeryLongFunction():
                AndAlsoALongReturnType {
            }
            """.trimIndent()
        functionReturnTypeSpacingRuleAssertThat(code)
            .withEditorConfigOverride(MAX_LINE_LENGTH_PROPERTY to 80)
            .hasNoLintViolations()
    }

    @Test
    fun `Given a function with parameters where joining return type to colon does not exceed max line length then do reformat`() {
        val code =
            """
            fun thisIsAVeryVeryVeryVeryVeryVeryVeryVeryVeryVeryVeryVeryVeryVeryVeryVeryVeryVeryVeryLongFunction(
                param: String
            ):
                AndAlsoALongReturnType {
            }
            """.trimIndent()
        val formattedCode =
            """
            fun thisIsAVeryVeryVeryVeryVeryVeryVeryVeryVeryVeryVeryVeryVeryVeryVeryVeryVeryVeryVeryLongFunction(
                param: String
            ): AndAlsoALongReturnType {
            }
            """.trimIndent()
        functionReturnTypeSpacingRuleAssertThat(code)
            .withEditorConfigOverride(MAX_LINE_LENGTH_PROPERTY to 80)
            .hasLintViolation(3, 2, "Single space expected between colon and return type")
            .isFormattedAs(formattedCode)
    }
}
