261→ * added after the last child leaf.
262→ */
263→public fun ASTNode.upsertWhitespaceAfterMe(text: String) {
264→    if (this is LeafElement) {
265→        if (this.elementType == WHITE_SPACE) {
266→            return replaceWhitespaceWith(text)
267→        }
268→        val next = treeNext ?: nextLeaf()
269→        if (next != null && next.elementType == WHITE_SPACE) {
270→            next.replaceWhitespaceWith(text)
271→        } else {
272→            PsiWhiteSpaceImpl(text).also { psiWhiteSpace ->
273→                (psi as LeafElement).rawInsertAfterMe(psiWhiteSpace)
274→            }
275→        }
276→    } else {
277→        lastChildLeafOrSelf().upsertWhitespaceAfterMe(text)
278→    }
279→}
