public class FunctionReturnTypeSpacingRule :
    StandardRule(
        id = "function-return-type-spacing",
        usesEditorConfigProperties = setOf(MAX_LINE_LENGTH_PROPERTY),
    ),
    Rule.Experimental {
    private var maxLineLength = MAX_LINE_LENGTH_PROPERTY.defaultValue

    override fun beforeFirstNode(editorConfig: EditorConfig) {
        maxLineLength = editorConfig[MAX_LINE_LENGTH_PROPERTY]
    }

    override fun beforeVisitChildNodes(
        node: ASTNode,
        autoCorrect: Boolean,
        emit: (offset: Int, errorMessage: String, canBeAutoCorrected: Boolean) -> Unit,
    ) {
        node
            .takeIf { node.elementType == FUN }
            ?.let { node.findChildByType(COLON) }
            ?.let { colonNode ->
                removeWhiteSpaceBetweenClosingParenthesisAndColon(colonNode, emit, autoCorrect)
                fixWhiteSpaceBetweenColonAndReturnType(colonNode, emit, autoCorrect)
            }
    }

    private fun removeWhiteSpaceBetweenClosingParenthesisAndColon(
        node: ASTNode,
        emit: (offset: Int, errorMessage: String, canBeAutoCorrected: Boolean) -> Unit,
        autoCorrect: Boolean,
    ) {
        require(node.elementType == COLON)
        node
            .prevLeaf()
            ?.takeIf { it.elementType == WHITE_SPACE }
            ?.let { whitespaceBeforeColonNode ->
                if (whitespaceBeforeColonNode.textContains('\n') &&
                    maxLineLength != Int.MAX_VALUE &&
                    exceedsMaxLineLengthIfJoinedBefore(node, whitespaceBeforeColonNode)
                ) {
                    return
                }
                emit(whitespaceBeforeColonNode.startOffset, "Unexpected whitespace", true)
                if (autoCorrect) {
                    whitespaceBeforeColonNode.treeParent?.removeChild(whitespaceBeforeColonNode)
                }
            }
    }

    private fun exceedsMaxLineLengthIfJoinedBefore(
        colonNode: ASTNode,
        whitespaceBeforeColon: ASTNode,
    ): Boolean {
        val prevLeaf = whitespaceBeforeColon.prevLeaf() ?: return false
        val lengthBefore = prevLeaf.column - 1 + prevLeaf.textLength
        return lengthBefore + lengthOfFirstLine(colonNode) > maxLineLength
    }

    private fun fixWhiteSpaceBetweenColonAndReturnType(
        node: ASTNode,
        emit: (offset: Int, errorMessage: String, canBeAutoCorrected: Boolean) -> Unit,
        autoCorrect: Boolean,
    ) {
        require(node.elementType == COLON)
        val whiteSpaceAfterColon = node.nextLeaf()?.takeIf { it.elementType == WHITE_SPACE }
        if (whiteSpaceAfterColon?.text != " ") {
            if (whiteSpaceAfterColon != null &&
                whiteSpaceAfterColon.textContains('\n') &&
                maxLineLength != Int.MAX_VALUE &&
                exceedsMaxLineLengthIfJoinedAfter(node, whiteSpaceAfterColon)
            ) {
                return
            }
            emit(node.startOffset, "Single space expected between colon and return type", true)
            if (autoCorrect) {
                node.upsertWhitespaceAfterMe(" ")
            }
        }
    }

    private fun exceedsMaxLineLengthIfJoinedAfter(
        colonNode: ASTNode,
        whiteSpaceAfterColon: ASTNode,
    ): Boolean {
        val nextLeaf = whiteSpaceAfterColon.nextLeaf() ?: return false
        return colonNode.column + 1 + lengthOfFirstLine(nextLeaf) > maxLineLength
    }

    private fun lengthOfFirstLine(node: ASTNode): Int {
        var length = 0
        var curr: ASTNode? = node
        while (curr != null && !curr.textContains('\n')) {
            length += curr.textLength
            curr = curr.nextLeaf()
        }
        if (curr != null && curr.textContains('\n')) {
            length += curr.text.substringBefore('\n').length
        }
        return length
    }
