 16→public fun ASTNode.nextLeaf(
 17→    includeEmpty: Boolean = false,
 18→    skipSubtree: Boolean = false,
 19→): ASTNode? {
 20→    var n = if (skipSubtree) this.lastChildLeafOrSelf().nextLeafAny() else this.nextLeafAny()
 21→    if (!includeEmpty) {
 22→        while (n != null && n.textLength == 0) {
 23→            n = n.nextLeafAny()
 24→        }
 25→    }
 26→    return n
 27→}
 28→
 29→public fun ASTNode.nextLeaf(p: (ASTNode) -> Boolean): ASTNode? {
 30→    var n = this.nextLeafAny()
 31→    while (n != null && !p(n)) {
 32→        n = n.nextLeafAny()
 33→    }
 34→    return n
 35→}
 36→
 37→private fun ASTNode.nextLeafAny(): ASTNode? {
 38→    var n = this
 39→    if (n.firstChildNode != null) {
 40→        do {
 41→            n = n.firstChildNode
 42→        } while (n.firstChildNode != null)
 43→        return n
 44→    }
 45→    return n.nextLeafStrict()
 46→}
 47→
 48→private fun ASTNode.nextLeafStrict(): ASTNode? {
 49→    val nextSibling: ASTNode? = treeNext
 50→    if (nextSibling != null) {
 51→        return nextSibling.firstChildLeafOrSelf()
 52→    }
 53→    return treeParent?.nextLeafStrict()
 54→}
