224→/**
225→ * Updates or inserts a new whitespace element with [text] before the given node. If the node itself is a whitespace
226→ * then its contents is replaced with [text]. If the node is a (nested) composite element, the whitespace element is
227→ * added after the previous leaf node.
228→ */
229→public fun ASTNode.upsertWhitespaceBeforeMe(text: String) {
230→    if (this is LeafElement) {
231→        if (this.elementType == WHITE_SPACE) {
232→            return replaceWhitespaceWith(text)
233→        }
234→        val previous = treePrev ?: prevLeaf()
235→        if (previous != null && previous.elementType == WHITE_SPACE) {
236→            previous.replaceWhitespaceWith(text)
237→        } else {
238→            PsiWhiteSpaceImpl(text).also { psiWhiteSpace ->
239→                (psi as LeafElement).rawInsertBeforeMe(psiWhiteSpace)
240→            }
241→        }
242→    } else {
243→        val prevLeaf =
244→            requireNotNull(prevLeaf()) {
245→                "Can not upsert a whitespace if the first node is a non-leaf node"
246→            }
247→        prevLeaf.upsertWhitespaceAfterMe(text)
248→    }
249→}
250→
251→private fun ASTNode.replaceWhitespaceWith(text: String) {
252→    require(this.elementType == WHITE_SPACE)
253→    if (this.text != text) {
254→        (this.psi as LeafElement).rawReplaceWithText(text)
255→    }
256→}
257→
258→/**
259→ * Updates or inserts a new whitespace element with [text] after the given node. If the node itself is a whitespace
260→ * then its contents is replaced with [text]. If the node is a (nested) composite element, the whitespace element is
261→ * added after the last child leaf.
262→ */
263→public fun ASTNode.upsertWhitespaceAfterMe(text: String) {
264→    if (this is LeafElement) {
265→        if (this.elementType == WHITE_SPACE) {
266→            return replaceWhitespaceWith(text)
267→        }
268→        val next = treeNext ?: nextLeaf()
269→        if (next != null && next.elementType == WHITE_SPACE) {
270→            next.replaceWhitespaceWith(text)
271→        } else {
272→            PsiWhiteSpaceImpl(text).also { psiWhiteSpace ->
273→                (psi as LeafElement).rawInsertAfterMe(psiWhiteSpace)
274→            }
275→        }
276→    } else {
277→        lastChildLeafOrSelf().upsertWhitespaceAfterMe(text)
278→    }
279→}
