307→/**
308→ *  Print content of a node and the element type of the node, its parent and its direct children. Utility is meant to
309→ *  be used during development only. Please do not remove.
310→ */
311→@Suppress("unused")
312→public fun ASTNode.logStructure(): ASTNode =
313→    also {
314→        println("Processing ${text.replaceTabAndNewline()} : Type $elementType with parent ${treeParent?.elementType} ")
315→        children()
316→            .toList()
317→            .map {
