322→private fun String.replaceTabAndNewline(): String = replace("\t", "\\t").replace("\n", "\\n")
323→
324→/**
325→ * Verifies that a leaf containing a newline exist in the closed range [from] - [to]. Also, returns true in case any of
326→ * the boundary nodes [from] or [to] contains a newline.
327→ */
328→public fun hasNewLineInClosedRange(
329→    from: ASTNode,
330→    to: ASTNode,
331→): Boolean =
332→    from.isWhiteSpaceWithNewline() ||
333→        leavesInOpenRange(from, to).any { it.textContains('\n') } ||
334→        to.isWhiteSpaceWithNewline()
335→
336→/**
337→ * Verifies that no leaf contains a newline in the closed range [from] - [to]. Also, the boundary nodes [from] and [to]
338→ * should not contain a newline.
339→ */
340→public fun noNewLineInClosedRange(
341→    from: ASTNode,
342→    to: ASTNode,
343→): Boolean =
344→    !from.isWhiteSpaceWithNewline() &&
345→        leavesInOpenRange(from, to).none { it.textContains('\n') } &&
346→        !to.isWhiteSpaceWithNewline()
347→
348→/**
349→ * Creates a sequence of leaf nodes in the open range [from] - [to]. This means that the boundary nodes are excluded
350→ * from the range in case they would happen to be a leaf node. In case [from] is a [CompositeElement] than the first
351→ * leaf node in the sequence is the first leaf node in this [CompositeElement]. In case [to] is a [CompositeElement]
352→ * than the last node in the sequence is the last leaf node prior to this [CompositeElement].
353→ */
354→public fun leavesInOpenRange(
355→    from: ASTNode,
356→    to: ASTNode,
357→): Sequence<ASTNode> =
358→    from
359→        .leaves()
360→        .takeWhile { it != to && it != to.firstChildNode }
