  2→
  3→import com.pinterest.ktlint.rule.engine.core.api.ElementType.COLON
  4→import com.pinterest.ktlint.rule.engine.core.api.ElementType.FUN
  5→import com.pinterest.ktlint.rule.engine.core.api.ElementType.WHITE_SPACE
  6→import com.pinterest.ktlint.rule.engine.core.api.Rule
  7→import com.pinterest.ktlint.rule.engine.core.api.RuleId
  8→import com.pinterest.ktlint.rule.engine.core.api.column
  9→import com.pinterest.ktlint.rule.engine.core.api.editorconfig.EditorConfig
 10→import com.pinterest.ktlint.rule.engine.core.api.editorconfig.MAX_LINE_LENGTH_PROPERTY
 11→import com.pinterest.ktlint.rule.engine.core.api.nextLeaf
 12→import com.pinterest.ktlint.rule.engine.core.api.prevLeaf
 13→import com.pinterest.ktlint.rule.engine.core.api.upsertWhitespaceAfterMe
 14→import com.pinterest.ktlint.ruleset.standard.StandardRule
 15→import org.jetbrains.kotlin.com.intellij.lang.ASTNode
 16→
 17→public class FunctionReturnTypeSpacingRule :
 18→    StandardRule(
 19→        id = "function-return-type-spacing",
 20→        usesEditorConfigProperties = setOf(MAX_LINE_LENGTH_PROPERTY),
 21→    ),
 22→    Rule.Experimental {
 23→    private var maxLineLength = MAX_LINE_LENGTH_PROPERTY.defaultValue
 24→
 25→    override fun beforeFirstNode(editorConfig: EditorConfig) {
 26→        maxLineLength = editorConfig[MAX_LINE_LENGTH_PROPERTY]
 27→    }
 28→
 29→    override fun beforeVisitChildNodes(
 30→        node: ASTNode,
 31→        autoCorrect: Boolean,
 32→        emit: (offset: Int, errorMessage: String, canBeAutoCorrected: Boolean) -> Unit,
 33→    ) {
 34→        node
 35→            .takeIf { node.elementType == FUN }
 36→            ?.let { node.findChildByType(COLON) }
 37→            ?.let { colonNode ->
 38→                removeWhiteSpaceBetweenClosingParenthesisAndColon(colonNode, emit, autoCorrect)
 39→                fixWhiteSpaceBetweenColonAndReturnType(colonNode, emit, autoCorrect)
 40→            }
 41→    }
 42→
 43→    private fun removeWhiteSpaceBetweenClosingParenthesisAndColon(
 44→        node: ASTNode,
 45→        emit: (offset: Int, errorMessage: String, canBeAutoCorrected: Boolean) -> Unit,
 46→        autoCorrect: Boolean,
 47→    ) {
 48→        require(node.elementType == COLON)
 49→        node
 50→            .prevLeaf()
 51→            ?.takeIf { it.elementType == WHITE_SPACE }
 52→            ?.let { whitespaceBeforeColonNode ->
 53→                if (whitespaceBeforeColonNode.textContains('\n') &&
 54→                    maxLineLength != Int.MAX_VALUE &&
 55→                    exceedsMaxLineLengthIfJoinedBefore(node, whitespaceBeforeColonNode)
 56→                ) {
 57→                    return
 58→                }
 59→                emit(whitespaceBeforeColonNode.startOffset, "Unexpected whitespace", true)
 60→                if (autoCorrect) {
 61→                    whitespaceBeforeColonNode.treeParent?.removeChild(whitespaceBeforeColonNode)
 62→                }
 63→            }
 64→    }
 65→
 66→    private fun exceedsMaxLineLengthIfJoinedBefore(
 67→        colonNode: ASTNode,
 68→        whitespaceBeforeColon: ASTNode,
 69→    ): Boolean {
 70→        val prevLeaf = whitespaceBeforeColon.prevLeaf() ?: return false
 71→        val lengthBefore = prevLeaf.column - 1 + prevLeaf.textLength
 72→        return lengthBefore + lengthOfFirstLine(colonNode) > maxLineLength
 73→    }
 74→
 75→    private fun fixWhiteSpaceBetweenColonAndReturnType(
 76→        node: ASTNode,
 77→        emit: (offset: Int, errorMessage: String, canBeAutoCorrected: Boolean) -> Unit,
 78→        autoCorrect: Boolean,
 79→    ) {
 80→        require(node.elementType == COLON)
 81→        val whiteSpaceAfterColon = node.nextLeaf()?.takeIf { it.elementType == WHITE_SPACE }
 82→        if (whiteSpaceAfterColon?.text != " ") {
 83→            if (whiteSpaceAfterColon != null &&
 84→                whiteSpaceAfterColon.textContains('\n') &&
 85→                maxLineLength != Int.MAX_VALUE &&
 86→                exceedsMaxLineLengthIfJoinedAfter(node, whiteSpaceAfterColon)
 87→            ) {
 88→                return
 89→            }
 90→            emit(node.startOffset, "Single space expected between colon and return type", true)
 91→            if (autoCorrect) {
 92→                node.upsertWhitespaceAfterMe(" ")
 93→            }
 94→        }
 95→    }
 96→
 97→    private fun exceedsMaxLineLengthIfJoinedAfter(
 98→        colonNode: ASTNode,
 99→        whiteSpaceAfterColon: ASTNode,
100→    ): Boolean {
101→        val nextLeaf = whiteSpaceAfterColon.nextLeaf() ?: return false
102→        return colonNode.column + 1 + lengthOfFirstLine(nextLeaf) > maxLineLength
103→    }
104→
105→    private fun lengthOfFirstLine(node: ASTNode): Int {
106→        var length = 0
107→        var curr: ASTNode? = node
108→        while (curr != null && !curr.textContains('\n')) {
109→            length += curr.textLength
110→            curr = curr.nextLeaf()
111→        }
112→        if (curr != null && curr.textContains('\n')) {
113→            length += curr.text.substringBefore('\n').length
114→        }
115→        return length
116→    }
117→}
